package pe.edu.utp.tmo.controller; import jakarta.validation.Valid; import java.security.Principal; import java.util.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import pe.edu.utp.tmo.dto.request.*; import pe.edu.utp.tmo.dto.response.TicketResponse; import pe.edu.utp.tmo.service.TicketService; @RestController @RequestMapping("/api/tickets") public class TicketController{ private final TicketService s; public TicketController(TicketService s){this.s=s;} @PostMapping ResponseEntity<TicketResponse> abrir(@Valid @RequestBody TicketCreateRequest r,Principal p){return ResponseEntity.status(HttpStatus.CREATED).body(s.abrirTicket(p.getName(),r));} @GetMapping("/mine") ResponseEntity<List<TicketResponse>> mine(Principal p){return ResponseEntity.ok(s.listarMisTickets(p.getName()));} @PutMapping("/{id}/close") ResponseEntity<TicketResponse> close(@PathVariable Long id,@Valid @RequestBody TicketCloseRequest r,Principal p){return ResponseEntity.ok(s.cerrarTicket(p.getName(),id,r));}}